///SB, DLT, 30/04/2026
/// <summary>
/// COC of standard method to add custom BatchId
/// </summary>
public void initFromInventTable(
    InventTable                 _inventTable,
    InventItemOrderSetupType    _setupType,
    InventDim                   _inventDimDefault
    )
{
    next initFromInventTable(_inventTable, _setupType, _inventDimDefault);

    if(ETGCanadaParameters::find().EnableDefaultBatchNumber == NoYes::Yes)
    {
        this.inventBatchId = _inventTable.ETGDefaultBatchNumber;
    }
}
